import { useNavigate } from "react-router-dom";
import Navbar from "../components/Navbar";
import Footer from "../components/Footer";

export default function Home() {

  const nav = useNavigate();

  return (
    <div style={styles.page}>

      <Navbar />

      <div style={styles.hero}>

        <div style={styles.left}>

          <h1 style={styles.heading}>
            Hire Skilled Daily Workers Easily
          </h1>

          <p style={styles.text}>
            Connect customers and workers instantly with
            our smart labour hiring platform.
          </p>

          <div style={styles.btnRow}>

            <button
              style={styles.customerBtn}
              onClick={() => nav("/login/customer")}
            >
              Customer Login
            </button>

            <button
              style={styles.labourBtn}
              onClick={() => nav("/login/labour")}
            >
              Labour Login
            </button>

          </div>

          <div style={styles.btnRow}>

            <button
              style={styles.outlineBtn}
              onClick={() => nav("/register/customer")}
            >
              Customer Register
            </button>

            <button
              style={styles.outlineBtn}
              onClick={() => nav("/register/labour")}
            >
              Labour Register
            </button>

          </div>

        </div>

        <div style={styles.right}>

          <div style={styles.card}>
            <h2>Popular Services</h2>

            <p>✔ Electrician</p>
            <p>✔ Painter</p>
            <p>✔ Plumber</p>
            <p>✔ Carpenter</p>
            <p>✔ House Cleaning</p>
          </div>

        </div>

      </div>

      <Footer />

    </div>
  );
}

const styles = {
  page: {
    background: "#f4f7fb",
    minHeight: "100vh",
    fontFamily: "Arial"
  },

  hero: {
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    padding: "70px"
  },

  left: {
    width: "50%"
  },

  heading: {
    fontSize: "55px",
    color: "#111827"
  },

  text: {
    color: "#6b7280",
    fontSize: "18px",
    lineHeight: "30px",
    marginTop: "20px"
  },

  btnRow: {
    display: "flex",
    gap: "15px",
    marginTop: "20px"
  },

  customerBtn: {
    background: "#2563eb",
    color: "white",
    border: "none",
    padding: "14px 24px",
    borderRadius: "10px"
  },

  labourBtn: {
    background: "#22c55e",
    color: "white",
    border: "none",
    padding: "14px 24px",
    borderRadius: "10px"
  },

  outlineBtn: {
    background: "white",
    border: "1px solid #ddd",
    padding: "14px 24px",
    borderRadius: "10px"
  },

  right: {
    width: "40%"
  },

  card: {
    background: "white",
    padding: "35px",
    borderRadius: "18px",
    boxShadow: "0 10px 25px rgba(0,0,0,0.08)"
  }
};
